- 'importance assigned' refers to the weightage;
- 'types of assessments' corresponds to the assessment types like exams, assignments, etc.;
- 'each course' refers to the specific module name.

sql:
SELECT DISTINCT i.instructor_name
FROM instructors i
INNER JOIN assessment_comments ac ON i.instructor_id = ac.instructor_id;

SELECT department_name, contact_email
FROM departments
WHERE head_id IN (SELECT instructor_id FROM instructors);

external_knowledge:
- Enthusiastic following = highest number of enrolled students;
- Educator = instructor;
- Class = module.

sql:
SELECT transcript_id, student_id, module_id, gpa 
FROM transcripts
WHERE gpa > 3.5;

SELECT module_id, AVG(gpa) AS average_gpa
FROM transcripts
GROUP BY module_id;

SELECT student_id, certificate_url
FROM certificates
WHERE student_id = 1;

SELECT m.module_name, i.instructor_name
FROM modules m
LEFT JOIN instructors i ON m.instructor_id = i.instructor_id;
